use std::thread;

fn main() {
    let initial_message = String::from("This data must live forever for the spawned thread.");

    // The 'static requirement forces us to move or clone owned data into the thread closure.
    let handle = thread::spawn(move || {
        println!("Background task started. It owns: {}", initial_message);
        thread::sleep(std::time::Duration::from_millis(10));
        println!("Background task finished successfully.");
    });

    // The main thread continues its work while the background job runs.
    println!("Main program continuing execution...");

    handle.join().unwrap();
    println!("Main program finished after waiting for background task.");
}

use std::thread;
use std::any::Any;

fn main() {
    let handle = thread::spawn(|| {
        loop {
            std::thread::sleep(std::time::Duration::from_millis(100));
            println!("Background worker is alive!");
        }
    });

    if let Err(e) = handle.join() {
        eprintln!("Error joining thread: {:?}", e);
    }
}

use std::thread;

fn main() {
    let data = String::from("Important data for the thread");

    // This will fail because 'data' is not 'static
    /*
    let handle = thread::spawn(|| {
        println!("Thread sees: {}", data);
    });
    handle.join().unwrap();
    */

    // To make it work, we must ensure the data lives long enough.
    let static_data: String = String::from("Data guaranteed to live forever");

    println!("Starting background task...");

    let handle = thread::spawn(move || {
        // The 'move' keyword transfers ownership, and the captured data must be 'static or owned by the closure.
        println!("Background process running. Captured value: {}", static_data);
    });

    // Wait for the spawned thread to finish its work demonstration
    handle.join().expect("Thread panicked");
    println!("Main program finished successfully.");
}

use std::thread;

struct TaskData {
    id: u32,
    message: String
}

fn main() {
    let initial_data = TaskData {
        id: 42,
        message: "Important setup data".to_string()
    };

    // This thread needs to own the data because 'static means it must live forever relative to the spawn point.
    let handle = thread::spawn(move || {
        println!("Background task started. ID: {}", initial_data.id);
        thread::sleep(std::time::Duration::from_millis(50));
        println!("Background task finished using data: {}", initial_data.message);
    });

    // Main thread continues working...
    println!("Main program proceeding while background work happens.");

    handle.join().unwrap();
    println!("All tasks complete.");
}

use std::thread;

struct PersistentData {
    value: i32,
}

impl Default for PersistentData {
    fn default() -> Self {
        PersistentData { value: 0 }
    }
}

fn main() {
    let data = PersistentData { value: 42 };

    let handle = thread::spawn(move || {
        println!("Background task started. Accessing value: {}", data.value);
        thread::sleep(std::time::Duration::from_millis(10));
    });

    println!("Main task continues immediately.");

    let _ = handle.join();
    println!("Program finished cleanly.");
}
